create database customer_behavior;
use customer_behavior;

select * from customers
limit 10;

-- what is the total rebenue generated by male vs female customers?

select gender,sum(purchased_amount) as revenue from customers
group by gender;

-- which customer used a discount but still spent more than the average purchase amount?

select customer_id,purchased_amount from customers
where discount_applied = 'Yes' and purchased_amount >= (select avg(purchased_amount) from customers);

-- which are the top  5 products with the highest average review rating?

select item_purchased, round(avg(review_rating),2) as avg_review_rating
from customers 
group by item_purchased
order by avg_review_rating desc
limit 5;

-- compare the average purchase amounts between standard and express shipping.

select shipping_type,round(avg(purchased_amount),2) from customers
where shipping_type in ('standard','express')
group by shipping_type;


-- Do subscribed customers spend more ? compare avergae spend and total revenue between subscribers and non-subscriber

select subscription_status,count(customer_id) as tota_customer,
avg(purchased_amount) as average_spend,
sum(purchased_amount) as total_revenue 
from customers
group by subscription_status
order by total_revenue,average_spend desc;



-- Which 5 products have the highest percentage of purchase with discounts applied?

select item_purchased,round(sum(case when discount_applied = 'Yes'then 1 else 0 end)/count(*)*100,2)
as discount_rate_percentage from customers
group by item_purchased
order by discount_rate_percentage desc
limit 5;

-- Segment customers into new, returing, and loyal based on their total 
-- number of previous purchases, and show the count of each segment

-- with customer_type as (
-- select customer_id,previous_purchases,
-- case 
-- when previous_purchases = 1 then 'New'
