-- else 'Loyal'
-- end as customer_segments
-- from customers
-- )

-- select customer_segments,count(*) as number_of_customers from customer_type
-- group by customer_segments;

select 
case 
when previous_purchases = 1 then 'New'
when previous_purchases between 2 and 10 then 'Returining'
else 'Loyal'
end as customer_segment , count(*) as number_of_customers from customers
group by customer_segment;


-- What are the top 3 most purchases products within each categorgory 

with item_count as (
select category,item_purchased,sum(purchased_amount) as total_amount ,count(customer_id) as total_orders,
row_number() over(partition by category order by count(customer_id) desc) as item_rank
from customers
group by category,item_purchased
)

select item_rank,category,item_purchased,total_orders from item_count
where item_rank <= 3;


-- Are customers who  are repeat buyers (more than 5 previous purchases) also likely to subscribtion

select * from customers limit 5;

select subscription_status,count(customer_id) as repeat_buyers from
customers 
where previous_purchases > 5
group by subscription_status;

-- What is the revenue contribute of each age group

select age_group,sum(purchased_amount) as total_revenue from customers 
group by age_group
order by total_revenue desc;